            u32 idx = *(u32 *)args;
            if (idx < t.count && t.views[idx].used) {
                t.views[idx].x += *(float *)(args + 4);
                t.views[idx].y += *(float *)(args + 8);
            }
        }
        store(id, &t);
    } else if (op == 18) {
