                t.dragging = (int)ni;
            }
            handled = 1;
            break;
        }
        store(id, &t);
        push(&handled, 4);
    }

    if (op == 32) {
        float x = 0.0f, y = 0.0f;
        if (t.dragging >= 0 && (u32)t.dragging < t.count && t.views[t.dragging].used) {
            x = t.views[t.dragging].x;
            y = t.views[t.dragging].y;
