extern __declspec(dllimport) void cvm_exec(const H h);
extern __declspec(dllimport) int cvm_ret(void);

static int zero32(const u8 *p) {
    for (int i = 0; i < 32; i++) if (p[i]) return 0;
    return 1;
}

