# Compile hash-named DLLs
def build(src_path, libs, label):
    tmp = f'mods\\_{label}.dll'
    cmd = ['gcc', '-shared', src_path, '-o', tmp] + libs
    r = subprocess.run(cmd, capture_output=True, text=True)
    if r.returncode:
        print(r.stderr)
        raise SystemExit(f'build fail {label}')
    data = open(tmp, 'rb').read()
    h = hashlib.sha256(data).hexdigest()
    dest = f'mods\\{h}.dll'
    if os.path.exists(dest):
        os.remove(dest)
    os.replace(tmp, dest)
    print(label, h)
    return h

